// src/components/StyleEditor/StyleEditor.jsx (упрощенная версия для теста)
import React from 'react';

const StyleEditor = ({ conferenceId, onSave, onClose }) => {
  console.log('StyleEditor mounted!', { conferenceId });
  
  return (
    <div style={{
      position: 'fixed',
      top: '50%',
      left: '50%',
      transform: 'translate(-50%, -50%)',
      backgroundColor: 'white',
      padding: '30px',
      borderRadius: '10px',
      boxShadow: '0 0 100px rgba(0,0,0,0.5)',
      zIndex: 9999,
      minWidth: '400px'
    }}>
      <h2>Редактор стилей (ТЕСТ)</h2>
      <p>ID конференции: {conferenceId}</p>
      <button onClick={onClose}>Закрыть</button>
      <button onClick={onSave}>Сохранить</button>
    </div>
  );
};

export default StyleEditor;
